import earlyAccessData from "../mockData/earlyAccessData";

export const EarlyAccessButton = ({ buttonData }) => {
  const { title } = buttonData;
  return (
    <div className="early_access_section__right">
      <button className="early_access_btn">{title}</button>
    </div>
  );
};

export const EarlyAccessContent = ({ contentData }) => {
  const { subtitle, title } = contentData;
  return (
    <div className="early_access_sectionleft">
      <h3 className="sectionsubtitle">{subtitle}</h3>
      <h2 className="sectiontitle">{title}</h2>
    </div>
  );
};

export const EarlyAccess = () => {
  const { ctaButton, earlyAccessContent } = earlyAccessData;

  return (
    <>
      <section className="section early_access_section">
        <div className="early_access_sectioncontent">
          <EarlyAccessContent contentData={earlyAccessContent} />
          <EarlyAccessButton buttonData={ctaButton} />
        </div>
      </section>
    </>
  );
};

export default EarlyAccess;
